/**
 * # Gnosis.TopologicalCinema — The Rotating Barcode Mirror
 *
 * Mirrors `Gnosis.TopologicalCinema` from `open-source/gnosis-math`.
 * Mechanizes the "Rotating Barcode" as a temporal video sequence.
 */

import {
  tritonRotation,
  forkChildrenConstructiveInterference,
} from "./pleromatic-monster-mesh";

/**
 * A 'Topological Frame' represents a single slice of the barcode.
 */
export interface TopologicalFrame {
  level: number;
  phase: 0 | 1 | 2;
}

/**
 * The 'Triton Shutter' advances the video by one rotation.
 */
export function advanceFrame(f: TopologicalFrame): TopologicalFrame {
  return {
    level: f.level,
    phase: tritonRotation(f.phase) as 0 | 1 | 2,
  };
}

/**
 * 'Pleromatic Playback' generates the stream of topological frames.
 */
export function* pleromaticPlayback(
  start: TopologicalFrame
): Generator<TopologicalFrame> {
  let current = start;
  while (true) {
    yield current;
    current = advanceFrame(current);
  }
}

/**
 * 'Bizarro Interpolation' calculates the sub-sample motion.
 * It shows how the three higher-scale candidates interference
 * at the lower bandwidth.
 */
export function getBizarroInterpolation(k: number) {
  const { children } = forkChildrenConstructiveInterference(k);
  return {
    candidates: children,
    focus: (phase: 0 | 1 | 2) => children[phase],
  };
}

/**
 * 'Pleromatic Zoom' calculates the resolution of the video
 * based on the closure tower level.
 */
export function getResolution(level: number): number {
  // Level 0 = 10 (Base Closure)
  // Level 1 = 30
  // Level 2 = 90
  // Level 3 = 270 (The "Monster Mesh" standard resolution)
  return 10 * Math.pow(3, level);
}

/**
 * Master Witness: Rotating Barcode Plays Video.
 */
export const TopologicalCinemaMaster = {
  isPeriodic: (f: TopologicalFrame) => {
    const f1 = advanceFrame(f);
    const f2 = advanceFrame(f1);
    const f3 = advanceFrame(f2);
    return f3.phase === f.phase;
  },
  
  hasMotion: (k: number) => {
    const interp = getBizarroInterpolation(k);
    return interp.candidates[0] !== interp.candidates[1];
  },

  getPlaybackSample: (start: TopologicalFrame, frames: number) => {
    const sequence: TopologicalFrame[] = [];
    const player = pleromaticPlayback(start);
    for (let i = 0; i < frames; i++) {
      sequence.push(player.next().value as TopologicalFrame);
    }
    return sequence;
  }
};
